161	  const deliveryId = webhookDef.extractDeliveryId(req.headers, parsedPayload);
162	  const eventType = webhookDef.extractEventType(req.headers, parsedPayload);
163	  const resourceId = webhookDef.extractResourceId(parsedPayload);
164	
165	  // Persist to DB
166	  await db
167	    .insert(gatewayWebhookDeliveries)
168	    .values({
169	      provider: providerSlug,
170	      deliveryId,
171	      eventType,
172	      installationId: null,
173	      status: "received",
174	      payload: JSON.stringify(parsedPayload),
175	      receivedAt: new Date(receivedAt).toISOString(),
176	    })
177	    .onConflictDoNothing();
178	
179	  // Dispatch Inngest event
180	  await inngest.send({
181	    id: `wh-${providerSlug}-${deliveryId}`,
